prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?name ?eventGatewayType ?gatewayDirection ?isClosed WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "f404135647444aedabe98bb54c000517" .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .

  ?gw a bboExt:EventBasedGateway .
  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?name . }
  OPTIONAL { ?gw bboExt:eventGatewayType ?eventGatewayType . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?gatewayDirection . }
  OPTIONAL { ?choreo bboExt:isClosed ?isClosed . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?idProp ?idValue WHERE {
  ?model a bboExt:Model .
  VALUES ?idProp { tai:normalizedId tai:originalId tai:corpusId tai:modelCreated }
  OPTIONAL { ?model tai:normalizedId ?idValue . BIND(tai:normalizedId AS ?idProp) }
}
LIMIT 25

